// itemHistoryRow is one purchase of a matched item.
type itemHistoryRow struct {
	TransactionDate string  `json:"transactionDate"`
	WarehouseName   string  `json:"warehouseName"`
	ItemNumber      string  `json:"itemNumber"`
	UPC             string  `json:"upc"`
	Description     string  `json:"description"`
	UnitPrice       float64 `json:"unitPrice"`
	Quantity        float64 `json:"quantity"`
	Amount          float64 `json:"amount"`
}

// matchItemHistory finds line items whose description, item number, or UPC
// contains query (case-insensitive), returning one row per purchase, sorted by
// date ascending so price drift over time reads top-to-bottom.
func matchItemHistory(receipts []costcoReceipt, query string) []itemHistoryRow {
	q := strings.ToLower(strings.TrimSpace(query))
	rows := []itemHistoryRow{}
	if q == "" {
		return rows
	}
	for _, r := range receipts {
		for _, it := range r.ItemArray {
			hay := strings.ToLower(strings.Join([]string{it.Description, it.Description2, it.ItemNumber.String(), it.UPC.String()}, " "))
			if !strings.Contains(hay, q) {
				continue
			}
			rows = append(rows, itemHistoryRow{
				TransactionDate: r.TransactionDate,
				WarehouseName:   r.WarehouseName,
				ItemNumber:      it.ItemNumber.String(),
				UPC:             it.UPC.String(),
				Description:     strings.TrimSpace(it.Description + " " + it.Description2),
				UnitPrice:       it.UnitPriceAmount.float(),
				Quantity:        it.Unit.float(),
				Amount:          it.Amount.float(),
			})
		}
	}
	sort.Slice(rows, func(i, j int) bool { return rows[i].TransactionDate < rows[j].TransactionDate })
	return rows
}

